$btn.trigger('click');

VV.Form.DoAjaxFormSave().then(function (resp) {
   //VV.Form.Global.DisplayMessaging('The form has been saved.', 'Save')
  window.opener.VV.Form.ReloadRepeatingRowControl('Special Permit RRC');
   VV.Form.Template.SaveSpecialPermit();
});
